query ProductConfiguration($configurableProductId: String!, $storeId: String!, $userId: String, $cultureName: String, $currencyCode: String) {
  productConfiguration(configurableProductId: $configurableProductId, storeId: $storeId, userId: $userId, cultureName: $cultureName, currencyCode: $currencyCode) {
    configurationSections {
      id name description isRequired type
      allowCustomText allowTextOptions maxLength dependsOnSectionId
      options { id text quantity product { id name slug code } listPrice { amount currency { code } } salePrice { amount currency { code } } extendedPrice { amount currency { code } } }
    }
  }
}

